    vector<long> dist1(MAXN, INF), dist2(MAXN, INF);
    dijkstra(graph, a, s, dist1);
    dijkstra(graph, b, t, dist2);

    vector<long> dvec(n + 1);
    for (int i = 1; i <= n; ++i) {
        dvec[i] = dist1[i] + dist2[i];
    }

    for (int i = n - 1; i >= 1; --i) {
        dvec[i] = min(dvec[i], dvec[i + 1]);
    }

    long init = 1e15;
    for (int i = 1; i <= n; ++i) {
        cout << init - dvec[i] << '\n';
    }

    return 0;
}

